import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the input length does not exceed the buffer size
        char[] buffer = new char[Math.min(name.length(), 10)];

        // Copy user input into the buffer with proper bounds checking
        System.arraycopy(name.toCharArray(), 0, buffer, 0, buffer.length);

        // Accessing an index within the buffer size
        if (buffer.length > 10) {
            System.out.println("Buffer overflow detected. Input truncated.");
        } else {
            System.out.println("Hello, " + new String(buffer));
        }
    }
}

